const SILVER_RATE_WINDOW_MS = 180000; 
const SILVER_RATE_MAX_DEVIATION = 0.30; 

const SILVER_RATE_MIN_SPAN_MS = SILVER_RATE_WINDOW_MS / 2; 
let silverRateBuffer = []; 

function computeSlidingSilverPerHour(buffer, now, currentBest) {
  const pruned = (buffer||[]).filter(s => (now - s.t) <= SILVER_RATE_WINDOW_MS && (now - s.t) >= 0);
  if (pruned.length === 0) return { ratePerHour: 0, eligible: false };
  const oldestT = pruned.reduce((min, s) => Math.min(min, s.t), now);
  const windowMs = Math.max(now - oldestT, 1000); 
  const total = pruned.reduce((sum, s) => sum + s.silver, 0);
  let ratePerHour = total / (windowMs / 3600000);
  let eligible = windowMs >= SILVER_RATE_MIN_SPAN_MS; 
  if (eligible && currentBest > 0) {
    const deviation = (ratePerHour - currentBest) / currentBest;
    if (deviation > SILVER_RATE_MAX_DEVIATION) {
      
      const biggest = pruned.reduce((max, s) => Math.max(max, s.silver), 0);
      const trimmedRate = (total - biggest) / (windowMs / 3600000);
      if (trimmedRate > currentBest) ratePerHour = trimmedRate;
      else eligible = false; 
    }
  }
  return { ratePerHour, eligible };
}

function pruneSilverRateBuffer(now) {
  now = now || Date.now();
  while (silverRateBuffer.length && (now - silverRateBuffer[0].t) > SILVER_RATE_WINDOW_MS) silverRateBuffer.shift();
}

const SILVER_HIST_WINDOW_MS = 3600000; 
let silverMinuteHistory = []; 

function pushSilverMinuteSample(hist, delta, now) {
  const t = Math.floor(now / 60000) * 60000;
  const lastB = hist[hist.length - 1];
  if (lastB && lastB.t === t) lastB.silver += delta;
  else hist.push({ t, silver: delta });
  while (hist.length && (now - hist[0].t) > SILVER_HIST_WINDOW_MS) hist.shift();
}

const KPM_RATE_WINDOW_MS = 180000; 
const KPM_RATE_MAX_DEVIATION = 0.30; 
const KPM_RATE_MIN_SPAN_MS = KPM_RATE_WINDOW_MS / 2; 
