    ctx.beginPath(); ctx.ellipse(-7.4,2.8,2.2,1.3,0,0,7); ctx.fill();
    ctx.beginPath(); ctx.ellipse(7.4,2.8,2.2,1.3,0,0,7); ctx.fill();
    
