    ctx.beginPath(); ctx.moveTo(-9,-27); ctx.quadraticCurveTo(-15,-12,-11-lungeAmt*.3,8); ctx.stroke();
    ctx.beginPath(); ctx.moveTo(9,-27); ctx.quadraticCurveTo(15,-12,11+lungeAmt*.5,8); ctx.stroke();
