    ctx.beginPath(); ctx.moveTo(-2.8,-9); ctx.lineTo(-5.6,-11.4); ctx.moveTo(2.8,-9.6); ctx.lineTo(5.4,-12); ctx.moveTo(0,-10.4); ctx.lineTo(0,-13.6); ctx.stroke();
    ctx.restore();
    
