function marketRequireAuth() {
  if (!sb || !currentUser) { alert('Connecte-toi pour accéder au marché.'); return false; }
  if (isGuest()) {
    alert(i18next.t('market:market.auth_verified_required'));
    return false;
  }
  return true;
}

$a('btnMarketTopbar').onclick = async () => {
  if (!marketRequireAuth()) return;
  if (!(typeof isAdmin === 'function' && isAdmin())) {
    try {
      const { data } = await sb.rpc('get_market_open');
      if (data === false) {
        alert(i18next.t('market:market.closed_for_maintenance'));
        return;
      }
    } catch(e) {}
  }
  $a('marketOverlay').classList.add('open');
  refreshCommonMarket();
  
  if (typeof maybeQueueTutorialById === 'function') maybeQueueTutorialById('market');
};
$a('closeMarket').onclick = () => $a('marketOverlay').classList.remove('open');

async function openMarketSellFor(item) {
  if (!marketRequireAuth()) return;
  if (!(typeof isAdmin === 'function' && isAdmin())) {
    try {
      const { data } = await sb.rpc('get_market_open');
      if (data === false) { alert(i18next.t('market:market.closed_for_maintenance')); return; }
    } catch(e) {}
  }
  $a('marketOverlay').classList.add('open');
  cmActiveCat = 'all'; cmDrilldownName = null;
  await refreshCommonMarket();
  const kind = item.kind, enhLv = item.enhLv || 0;
  const g = cmGroupForExactItem(item.name, kind, enhLv);
  cmSelectedKey = cmItemKey(kind, item.name, enhLv);
  renderCmListingsList();
  renderCmDetailPanel(g);
  const offerBtn = $a('cmSellOfferBtn');
  const offerForm = $a('cmSellOfferForm');
  if (offerBtn && offerForm && !offerForm.classList.contains('open')) offerBtn.click();
  if (typeof maybeQueueTutorialById === 'function') maybeQueueTutorialById('market');
}

function cmGroupForExactItem(name, kind, enhLv) {
  const items = cmListings.filter(l => l.item_name === name && l.item_kind === kind &&
    ((l.item_snapshot && l.item_snapshot.enhLv) || 0) === (enhLv || 0));
  const best = items.length ? items.reduce((a,b) => a.price < b.price ? a : b) : null;
  return { name, kind, lv: enhLv, best, items };
}
let marketMouseDownOnBackdrop = false;
$a('marketOverlay').addEventListener('mousedown', e => { marketMouseDownOnBackdrop = (e.target.id === 'marketOverlay'); });
$a('marketOverlay').addEventListener('click', e => { if (e.target.id === 'marketOverlay' && marketMouseDownOnBackdrop) $a('marketOverlay').classList.remove('open'); });

const MARKET_MATERIALS = [
  { name:'Pierre de Novice',   icon:ICO_MAT_NOVICE,     color:'#b8b8b8' },
  { name:'Pierre du Temps',    icon:ICO_MAT_TEMPS,      color:'#cfd8dc' },
  { name:'Pierre Noire',       icon:ICO_MAT_NOIRE,      color:'#7aa35e' },
  { name:'Pierre concentrée',  icon:ICO_MAT_CONCENTREE, color:'#6ea3c9' },
  { name:'Pierre de Caphras',  icon:ICO_MAT_CAPHRAS,    color:'#c9a55a' },
  
  { name:'Livre interdit',     icon:'📕',                color:'#6a4a8a' },
];

const MARKET_SELL_TAX_RATE = 0.35;

const CONCLAVE_SEAL_TAX_REDUCTION = 0.05;     
const CONCLAVE_SEAL_LISTING_FEE_REDUCTION = 0.03; 
const CONCLAVE_SEAL_SELL_GAIN_BONUS = 0.08;   
const CONCLAVE_SEAL_REGIONAL_BONUS_PCT = 0.02; 

function conclaveSealActive() { return !!(typeof S !== 'undefined' && S.hasConclaveMarchandsSeal); }

function conclaveSealEffectiveSellKeepFraction() {
  const base = 1 - MARKET_SELL_TAX_RATE;
  if (!conclaveSealActive()) return base;
  const reducedTax = base + CONCLAVE_SEAL_TAX_REDUCTION + CONCLAVE_SEAL_LISTING_FEE_REDUCTION;
  return reducedTax * (1 + CONCLAVE_SEAL_SELL_GAIN_BONUS);
}

function conclaveSealRegionalBonusPct(itemOriginTierId) {
  if (!conclaveSealActive() || !S.conclaveSealRegions) return 0;
  return S.conclaveSealRegions.includes(itemOriginTierId) ? CONCLAVE_SEAL_REGIONAL_BONUS_PCT : 0;
}

function itemOriginRegionTierId(zi) { return (typeof ZONES !== 'undefined' && ZONES[zi] && ZONES[zi].originTierId) || 'early'; }

function conclaveSealSlotBonus() {
  if (conclaveSealActive()) return (S.conclaveSealRegions || []).length;
  return (typeof CONCLAVE_SEAL_FRAGMENTS !== 'undefined') ? CONCLAVE_SEAL_FRAGMENTS.filter(f => typeof invSlotByKey === 'function' && invSlotByKey(f.key) !== -1).length : 0;
}

async function fetchConclaveSealAvgPrice(itemKey) {
  if (!conclaveSealActive() || !sb) return null;
  const { data, error } = await sb.from('market_trades').select('price').eq('item_key', itemKey).order('created_at', { ascending:false }).limit(10);
  if (error || !data || !data.length) return null;
  return Math.round(data.reduce((n,r) => n + Number(r.price), 0) / data.length);
}

